import { useEffect, useMemo, useState } from "react";
import { Link } from "react-router-dom";
import { fetchCustomers } from "../services/api";
import "../styles/CustomerList.css";

function CustomerList() {
  const [customers, setCustomers] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadCustomers = async () => {
      try {
        const response = await fetchCustomers();
        setCustomers(response.data || []);
      } catch (error) {
        setCustomers([]);
      } finally {
        setLoading(false);
      }
    };

    loadCustomers();
  }, []);

  const filteredCustomers = useMemo(() => {
    const query = searchTerm.trim().toLowerCase();
    if (!query) {
      return customers;
    }

    return customers.filter(
      (customer) =>
        customer.name?.toLowerCase().includes(query) || customer.phone?.toLowerCase().includes(query)
    );
  }, [customers, searchTerm]);

  return (
    <main className="customer-list-page py-4">
      <div className="container">
        <section className="list-header mb-4">
          <h1 className="list-title">Customer Ledger</h1>
          <p className="list-subtitle">Manage every customer and quickly update balances.</p>
        </section>

        <section className="list-card card border-0 shadow-sm">
          <div className="card-body">
            <div className="row g-3 align-items-center mb-3">
              <div className="col-md-8">
                <input
                  type="text"
                  className="form-control customer-search-input"
                  placeholder="Search by customer name or phone number"
                  value={searchTerm}
                  onChange={(event) => setSearchTerm(event.target.value)}
                />
              </div>
              <div className="col-md-4 text-md-end">
                <p className="result-count mb-0">{filteredCustomers.length} result(s)</p>
              </div>
            </div>

            <div className="table-responsive">
              <table className="table align-middle customer-table mb-0">
                <thead>
                  <tr>
                    <th>Name</th>
                    <th>Phone</th>
                    <th>Total Balance</th>
                    <th>Status</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {loading ? (
                    <tr>
                      <td colSpan="5" className="text-center py-4">
                        Loading customers...
                      </td>
                    </tr>
                  ) : filteredCustomers.length === 0 ? (
                    <tr>
                      <td colSpan="5" className="text-center py-4">
                        No customers found for your search.
                      </td>
                    </tr>
                  ) : (
                    filteredCustomers.map((customer) => (
                      <tr key={customer._id}>
                        <td>{customer.name}</td>
                        <td>{customer.phone}</td>
                        <td>Rs {(customer.totalBalance || 0).toLocaleString("en-IN")}</td>
                        <td>
                          <span
                            className={`status-pill ${
                              (customer.totalBalance || 0) > 0 ? "status-due" : "status-clear"
                            }`}
                          >
                            {(customer.totalBalance || 0) > 0 ? "Due" : "Clear"}
                          </span>
                        </td>
                        <td>
                          <Link
                            to={`/transactions?customerId=${customer._id}`}
                            className="btn btn-sm transaction-btn"
                          >
                            Add Transaction
                          </Link>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </div>
    </main>
  );
}

export default CustomerList;
